using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9: HasIndex throws for Cosmos entities — removed.
        // Cosmos indexing is managed via the container's indexing policy.

        modelBuilder.Entity<Blog>(b =>
        {
            // EF Core 9: discriminator property renamed from "Discriminator" to "$type".
            // Preserve old name so existing documents remain queryable.
            b.HasDiscriminator<string>("Discriminator");

            // EF Core 9: id no longer includes discriminator (was "Blog|1", now "1").
            // Preserve old format so existing documents are still found by key.
            b.HasRootDiscriminatorInJsonId(true);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

